		/* oms-inventory-inventoryChkBatch-sql-oracle.xml - insertIntfIvInfoMalToOms */
		INSERT INTO TORDER_INTF_MAL_REALTIMESTOCK
		(
			  ICKEY
            , OLNICKEY
            , REQUESTDT
            , IFID
            , INSERTDATE
            , INSERTURKEY
            , UPDATEDATE
            , UPDATEURKEY
		) VALUES (
	      	  #{ickey}
            , #{olnickey}
            , #{requestDt}
            , #{interfaceId}
		    , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
		    , #{interfaceUrkey}
		    , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
		    , #{interfaceUrkey}
		)

